def update_matrix(matrix, m, n):
    rows_to_mark = set()
    cols_to_mark = set()

    for i in range(m):
        for j in range(n):
            if matrix[i][j] == 0:
                rows_to_mark.add(i)
                cols_to_mark.add(j)

    for i in range(m):
        for j in range(n):
            if i in rows_to_mark or j in cols_to_mark:
                matrix[i][j] = 0

    return matrix

input_data = input().split()
m = int(input_data[0])
n = int(input_data[1])
matrix = []

for i in range(m):
    row_input = input().split()
    row = []
    for num in row_input:
        row.append(int(num))
    matrix.append(row)

updated_matrix = update_matrix(matrix, m, n)

for row in updated_matrix:
    for num in row:
        print(num, end=" ")
    print()
